                          <input placeholder="Add..." className="bg-transparent text-[10px] font-bold outline-none w-24 p-1" onKeyDown={e => { if(e.key === 'Enter') { handleAddTaxonomy('categories', e.currentTarget.value); e.currentTarget.value = ''; } }} />
                       </div>
