                       <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Modelo de Texto</label>
                       <select value={appConfig.config?.aiModelText} onChange={e => setAppConfig({...appConfig, config: { ...appConfig.config!, aiModelText: e.target.value as any }})} className="w-full bg-gray-50 p-5 rounded-2xl font-bold text-xs">
                          <option value="gemini-3-pro-preview">Gemini 3 Pro (Recomendado)</option>
                          <option value="gemini-3-flash-preview">Gemini 3 Flash (Veloz)</option>
                       </select>
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-4">
                           <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Max Tokens</label>
                           <input type="number" value={appConfig.config?.aiMaxTokens} onChange={e => setAppConfig({...appConfig, config: { ...appConfig.config!, aiMaxTokens: parseInt(e.target.value) }})} className="w-full bg-gray-50 p-5 rounded-2xl font-bold text-xs" />
                        </div>
                        <div className="space-y-4">
                           <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Thinking Budget</label>
                           <input type="number" value={appConfig.config?.aiThinkingBudget} onChange={e => setAppConfig({...appConfig, config: { ...appConfig.config!, aiThinkingBudget: parseInt(e.target.value) }})} className="w-full bg-gray-50 p-5 rounded-2xl font-bold text-xs" />
                        </div>
                    </div>
                 </div>
              </section>

              {/* 4. Auditoria de Status */}
              <section className="space-y-8 pt-10 border-t border-gray-50">
                 <div className="flex items-center gap-4">
                    <div className="w-10 h-10 bg-emerald-50 rounded-xl flex items-center justify-center text-lg">📡</div>
                    <h3 className="text-xl font-black text-gray-900 uppercase tracking-tighter">4. Status da Infraestrutura</h3>
                 </div>
                 <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                    <div className="p-6 bg-gray-50 rounded-3xl flex justify-between items-center">
                       <span className="text-[10px] font-black text-gray-400 uppercase">API Key IA</span>
                       <span className="px-3 py-1 bg-green-100 text-green-700 rounded-full text-[9px] font-black uppercase tracking-widest">Configurada</span>
                    </div>
                    <div className="p-6 bg-gray-50 rounded-3xl flex justify-between items-center">
                       <span className="text-[10px] font-black text-gray-400 uppercase">Supabase DB</span>
                       <span className="px-3 py-1 bg-green-100 text-green-700 rounded-full text-[9px] font-black uppercase tracking-widest">Conectado</span>
                    </div>
                    <div className="p-6 bg-gray-50 rounded-3xl flex justify-between items-center">
                       <span className="text-[10px] font-black text-gray-400 uppercase">Google Workspace</span>
                       <span className="px-3 py-1 bg-blue-100 text-blue-700 rounded-full text-[9px] font-black uppercase tracking-widest">Ativo</span>
                    </div>
                 </div>
              </section>
           </div>
        </div>
      )}
    </div>
  );
};

