  const [isSyncing, setIsSyncing] = useState(false);
  const [isInitialLoading, setIsInitialLoading] = useState(true);
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null);
  const [searchTerm, setSearchTerm] = useState('');

  const [variableInputs, setVariableInputs] = useState<Record<string, { label: string, valor: string }>>({});
  const [deliverableInputs, setDeliverableInputs] = useState<Record<string, string>>({});

  const fileInputRef = useRef<HTMLInputElement>(null);

  const [goals, setGoals] = useState<MonthlyGoal[]>([]);
  const [historyRealized, setHistoryRealized] = useState<Record<string, number>>({});

  const [aiConfig, setAiConfig] = useState<AIConfig>({
    systemInstruction: "",
    architectInstruction: "",
    temperature: 0.8,
    maxOutputTokens: 6000,
    thinkingBudget: 4000
  });

  const [appConfig, setAppConfig] = useState<AppCustomization>({
    companyName: "PhantLab",
    systemLogoUrl: "http://phant.com.br/uploads/simbolo_roxo.png",
    proposalLogoUrl: "http://phant.com.br/uploads/logo_light.png",
    primaryColor: "#2563eb",
    config: {
      categories: ["Direção", "Propagação", "Aceleração"],
      subCategories: ["Marca & Cultura", "Crescimento (Growth)", "Tecnologia", "Cursos & Mentorias"],
      durations: ["30 dias", "90 dias", "6 meses", "12 meses", "Recorrente"],
      maturities: ["Base", "Pro", "Advanced"],
      tags: ["High Ticket", "Recorrente", "Setup Requerido", "Escalável"],
      defaultProposalSections: {
        cover: true,
        strategicMap: true,
        tacticalScope: true,
        finalInvestment: true,
        backCover: true
      },
      slaThreshold: 100000,
      aiModelText: 'gemini-3-pro-preview',
      aiModelImage: 'gemini-3-pro-image-preview',
      aiMaxTokens: 8000,
      aiThinkingBudget: 4000,
      driveFolderId: "1-01ahpyVthGXZJNUH5rZCjFKxqCm8sOI",
      syncJobId: "d11a1e38-414b-4c69-bb58-9e655f0e2d29",
      enabledModules: ["dashboard", "copilot", "fichario", "catalogo", "pdf_builder"]
    }
  });

  const showToast = (message: string, type: 'success' | 'error' = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 3000);
  };

  const loadAllData = useCallback(async () => {
    setIsInitialLoading(true);
    try {
      const sols = await SupabaseService.fetchSolutions().catch(() => []);
      const ai = await SupabaseService.fetchAIConfig().catch(() => null);
      const branding = await SupabaseService.fetchAppConfig().catch(() => null);
      const loadedGoals = await SupabaseService.fetchGoals().catch(() => []);
      const history = await SupabaseService.fetchProposalsHistory().catch(() => []);

      const realizedMap: Record<string, number> = {};
      history?.forEach(p => {
        if (p.created_at) {
          const monthKey = new Date(p.created_at).toISOString().slice(0, 7);
          realizedMap[monthKey] = (realizedMap[monthKey] || 0) + (p.total_value || 0);
        }
      });

      if (sols) setSolutions(sols);
      if (ai) setAiConfig(ai);
      if (branding) setAppConfig(branding);
      setGoals(generateGoalList(loadedGoals));
      setHistoryRealized(realizedMap);
    } finally {
      setIsInitialLoading(false);
    }
  }, []);

  const generateGoalList = (existing: MonthlyGoal[]) => {
    const list = [...existing];
    const today = new Date();
    for (let i = -6; i <= 6; i++) {
        const d = new Date(today.getFullYear(), today.getMonth() + i, 1);
        const key = d.toISOString().slice(0, 7);
        if (!list.find(g => g.month === key)) {
            list.push({ month: key, target: 0 });
        }
    }
    return list.sort((a, b) => b.month.localeCompare(a.month));
  };

  useEffect(() => { loadAllData(); }, [loadAllData]);

  const handleSyncSolutions = async () => {
    if (isSyncing) return;
    setIsSyncing(true);
    try {
      const result = await SupabaseService.syncSolutions(solutions);
      if (result.success) showToast("Catálogo sincronizado com a Nuvem");
      else showToast("Erro na sincronia: " + result.message, "error");
    } catch (err) {
      showToast("Falha na conexão com o servidor", "error");
    } finally {
      setIsSyncing(false);
    }
  };

  const handleMagicFill = async (id: string | number) => {
    const item = solutions.find(s => s.id === id);
    if (!item || !item.solucao) return;
    setIsMagicFilling(id);
    try {
      const details = await suggestSolutionDetails(item.solucao);
      setSolutions(prev => prev.map(s => s.id === id ? { ...s, ...details } : s));
      showToast("IA gerou os detalhes conforme suas instruções!");
    } catch (err) {
      showToast("Erro na IA", "error");
    } finally {
      setIsMagicFilling(null);
    }
  };

  const handleGenerateDeliverables = async (id: string | number) => {
    const item = solutions.find(s => s.id === id);
    if (!item || !item.solucao) return;
    setIsGeneratingDeliverables(id);
    try {
      const tasks = await generateSolutionDeliverables(item.solucao, item.descricao || "");
      if (tasks.length > 0) {
        setSolutions(prev => prev.map(s => s.id === id ? { ...s, entregaveis: tasks } : s));
        showToast("Fases do cronograma geradas pela IA!");
      }
    } catch (err) {
      showToast("Erro ao gerar fases", "error");
    } finally {
      setIsGeneratingDeliverables(null);
    }
  };

  const handleImportDocx = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsImporting(true);
    try {
      const arrayBuffer = await file.arrayBuffer();
      const result = await mammoth.extractRawText({ arrayBuffer });
      const text = result.value;
      const newItems = await parseBulkSolutions(text);
      if (newItems && newItems.length > 0) {
        const formatted: SolutionItem[] = newItems.map((item, i) => ({
          ...item,
          id: `imp-${Date.now()}-${i}`,
          categoria: item.categoria || appConfig.config?.categories[0] || 'Direção',
          subcategoria: item.subcategoria || appConfig.config?.subCategories[0] || 'Marca & Cultura',
          duracao: item.duracao || appConfig.config?.durations[0] || '90 dias',
          maturidade: item.maturidade || appConfig.config?.maturities[0] || 'Base',
          valor_base_num: item.valor_base_num || 0,
          variaveis_opcionais: [],
          entregaveis: [],
          fee_mensal: item.fee_mensal || "R$ 0",
          promessa: item.promessa || ""
        } as SolutionItem));
        setSolutions(prev => [...prev, ...formatted]);
        showToast(`${formatted.length} soluções importadas!`);
      }
    } catch (err) {
      showToast("Erro ao processar arquivo", "error");
    } finally {
      setIsImporting(false);
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  const addSolution = () => {
    const newItem: SolutionItem = {
      id: `new-${Date.now()}`,
      solucao: "Nova Solução",
      promessa: "Promessa de valor",
      categoria: appConfig.config?.categories[0] || "Direção",
      subcategoria: appConfig.config?.subCategories[0] || "Marca & Cultura",
      duracao: appConfig.config?.durations[0] || "90 dias",
      maturidade: appConfig.config?.maturities[0] || "Base",
      fee_mensal: "R$ 0",
      valor_base_num: 0,
      variaveis_opcionais: [],
      entregaveis: [],
      dica_venda: ""
    };
    setSolutions([newItem, ...solutions]);
    setExpandedId(newItem.id);
  };

  const updateSolution = (id: string | number, field: keyof SolutionItem, value: any) => {
    setSolutions(prev => prev.map(s => s.id === id ? { ...s, [field]: value } : s));
  };

  const removeSolution = (id: string | number) => {
    if (confirm("Deseja remover esta solução?")) {
      setSolutions(prev => prev.filter(s => s.id !== id));
      if (expandedId === id) setExpandedId(null);
    }
  };

  const toggleFavorite = (id: string | number) => {
    setSolutions(prev => prev.map(s => s.id === id ? { ...s, is_favorite: !s.is_favorite } : s));
  };

  const handleAddVariable = (solutionId: string | number) => {
    const input = variableInputs[String(solutionId)] || { label: '', valor: '' };
    if (!input.label.trim()) return;
    const valorNum = parseFloat(input.valor) || 0;
    setSolutions(prev => prev.map(s => {
       if (s.id === solutionId) {
          const currentVars = s.variaveis_opcionais || [];
          return { ...s, variaveis_opcionais: [...currentVars, { label: input.label, valor: valorNum }] };
       }
       return s;
    }));
    setVariableInputs(prev => ({ ...prev, [String(solutionId)]: { label: '', valor: '' } }));
  };

  const handleRemoveVariable = (solutionId: string | number, index: number) => {
     setSolutions(prev => prev.map(s => {
        if (s.id === solutionId) {
           const newVars = [...(s.variaveis_opcionais || [])];
           newVars.splice(index, 1);
           return { ...s, variaveis_opcionais: newVars };
        }
        return s;
     }));
  };

  const handleAddDeliverable = (solutionId: string | number) => {
    const text = deliverableInputs[String(solutionId)] || '';
    if (!text.trim()) return;
    setSolutions(prev => prev.map(s => {
      if (s.id === solutionId) {
        const current = s.entregaveis || [];
        return { ...s, entregaveis: [...current, text.trim()] };
      }
      return s;
    }));
    setDeliverableInputs(prev => ({ ...prev, [String(solutionId)]: '' }));
  };

  const handleRemoveDeliverable = (solutionId: string | number, index: number) => {
    setSolutions(prev => prev.map(s => {
      if (s.id === solutionId) {
        const current = [...(s.entregaveis || [])];
        current.splice(index, 1);
        return { ...s, entregaveis: current };
      }
      return s;
    }));
  };

  const toggleSolutionTag = (solutionId: string | number, tag: string) => {
    setSolutions(prev => prev.map(s => {
      if (s.id === solutionId) {
        const currentTags = s.tags || [];
        const nextTags = currentTags.includes(tag) 
          ? currentTags.filter(t => t !== tag) 
          : [...currentTags, tag];
        return { ...s, tags: nextTags };
      }
      return s;
    }));
  };

  const saveAIConfig = async () => {
    try {
      const res = await SupabaseService.syncAIConfig(aiConfig);
      if (res.success) showToast("Configuração de IA salva");
      else showToast("Erro ao salvar IA", "error");
    } catch (err) {
      showToast("Erro de rede ao salvar", "error");
    }
  };

  const saveCustomization = async () => {
    if (isSyncing) return;
    setIsSyncing(true);
    try {
      const res = await SupabaseService.syncAppConfig(appConfig);
      if (res.success) {
        showToast("Governança atualizada!");
        setTimeout(() => window.location.reload(), 1000);
      } else {
        showToast("Erro ao salvar", "error");
      }
    } catch {
      showToast("Falha de rede", "error");
    } finally {
      setIsSyncing(false);
    }
  };

  const handleAddTaxonomy = (field: keyof SystemConfig, value: string) => {
    if (!value.trim() || !appConfig.config) return;
    const currentList = (appConfig.config[field] as string[]) || [];
    if (currentList.includes(value)) return;
    setAppConfig({
      ...appConfig,
      config: { ...appConfig.config, [field]: [...currentList, value.trim()] }
    });
  };

  const handleRemoveTaxonomy = (field: keyof SystemConfig, index: number) => {
    if (!appConfig.config) return;
    const currentList = [...((appConfig.config[field] as string[]) || [])];
    currentList.splice(index, 1);
    setAppConfig({
      ...appConfig,
      config: { ...appConfig.config, [field]: currentList }
    });
  };

  const toggleModule = (moduleId: string) => {
    if (!appConfig.config) return;
    const current = appConfig.config.enabledModules || [];
    const next = current.includes(moduleId) 
      ? current.filter(id => id !== moduleId) 
      : [...current, moduleId];
    setAppConfig({
      ...appConfig,
      config: { ...appConfig.config, enabledModules: next }
    });
  };

  const updateGoal = (month: string, val: number) => {
    setGoals(prev => prev.map(g => g.month === month ? { ...g, target: val } : g));
  };

  const saveGoals = async () => {
    setIsSyncing(true);
    try {
      await SupabaseService.syncGoals(goals);
      showToast("Metas salvas!");
    } finally { setIsSyncing(false); }
  };

  const formatMonth = (m: string) => {
    const [y, month] = m.split('-');
    return new Date(parseInt(y), parseInt(month) - 1, 1).toLocaleDateString('pt-BR', { month: 'long', year: 'numeric' });
  };

  const formatCurrency = (val: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  const filteredSolutions = solutions
    .filter(s => s.solucao.toLowerCase().includes(searchTerm.toLowerCase()))
    .sort((a, b) => (a.is_favorite === b.is_favorite ? 0 : a.is_favorite ? -1 : 1));

  if (isInitialLoading) {
    return <div className="h-96 flex items-center justify-center font-black text-gray-300 uppercase tracking-widest animate-pulse">Carregando Governança...</div>;
  }

  return (
    <div className="max-w-7xl mx-auto space-y-12 pb-40 px-4">
      {toast && (
        <div className={`fixed top-10 right-10 z-[200] px-8 py-4 rounded-2xl shadow-2xl font-black text-xs uppercase tracking-widest bg-black text-white`}>
          {toast.message}
        </div>
      )}

      <header className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6">
        <div>
          <h1 className="text-6xl font-black text-gray-900 tracking-tighter leading-none mb-4">Administração</h1>
          <p className="text-gray-400 text-xl font-medium tracking-tight">Painel de Controle do Arquiteto</p>
        </div>
        <div className="flex bg-white p-1.5 rounded-2xl shadow-sm border border-gray-100 flex-wrap gap-1">
          {(['solutions', 'metas', 'system'] as const).map(tab => (
            <button
              key={tab}
              onClick={() => setActiveTab(tab)}
              className={`px-6 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === tab ? 'bg-black text-white shadow-lg' : 'text-gray-400 hover:text-black'}`}
            >
              {tab === 'solutions' ? 'Catálogo' : tab === 'metas' ? 'Metas' : 'Sistema'}
            </button>
          ))}
        </div>
      </header>

      {/* RENDER SOLUTIONS TAB */}
      {activeTab === 'solutions' && (
        <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
          <div className="flex flex-col md:flex-row gap-4 justify-between items-center bg-white p-8 rounded-[32px] border border-gray-100 shadow-sm">
            <div className="flex-1 w-full md:w-auto relative">
               <input 
                  type="text" 
                  placeholder="Buscar solução..." 
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  className="w-full pl-12 pr-4 py-4 bg-gray-50 rounded-2xl font-bold text-sm focus:bg-white border border-transparent focus:border-brand outline-none transition-all"
               />
               <svg className="w-5 h-5 text-gray-400 absolute left-4 top-1/2 -translate-y-1/2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"/></svg>
            </div>

            <div className="flex gap-4 w-full md:w-auto overflow-x-auto pb-2 md:pb-0">
              <button onClick={addSolution} className="px-6 py-4 bg-black text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl hover:scale-105 transition-all whitespace-nowrap">+ Nova Solução</button>
              <button onClick={() => fileInputRef.current?.click()} disabled={isImporting} className="px-6 py-4 bg-gray-50 border border-gray-200 text-gray-900 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-gray-100 transition-all flex items-center gap-2 whitespace-nowrap">
                {isImporting ? 'Importando...' : 'Importar DOCX'}
              </button>
              <input type="file" ref={fileInputRef} onChange={handleImportDocx} accept=".docx" className="hidden" />
              <button onClick={handleSyncSolutions} disabled={isSyncing} className={`px-8 py-4 ${isSyncing ? 'bg-gray-400' : 'bg-brand'} text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl hover:bg-blue-700 transition-all whitespace-nowrap`}>
                {isSyncing ? 'Salvando...' : 'Sincronizar'}
              </button>
            </div>
          </div>

          <div className="bg-white rounded-[32px] border border-gray-100 shadow-sm overflow-hidden">
            <div className="divide-y divide-gray-50">
              {filteredSolutions.map((item) => (
                <div key={item.id} className="transition-all">
                  <div 
                    className={`flex items-center justify-between p-6 hover:bg-gray-50 cursor-pointer transition-colors ${expandedId === item.id ? 'bg-gray-50' : ''}`}
                    onClick={() => setExpandedId(expandedId === item.id ? null : item.id)}
                  >
                    <div className="flex items-center gap-6 flex-1 min-w-0">
                      <button 
                        onClick={(e) => { e.stopPropagation(); toggleFavorite(item.id); }}
                        className={`transition-all ${item.is_favorite ? 'text-amber-500 scale-125' : 'text-gray-200 hover:text-amber-300'}`}
                      >
                        ★
                      </button>
                      <div className="min-w-0">
                        <p className="font-black text-lg text-gray-900 truncate tracking-tight">{item.solucao}</p>
                        <div className="flex gap-2 mt-1">
                           <span className="px-2 py-0.5 bg-gray-100 text-[8px] font-black uppercase tracking-widest text-gray-500 rounded">{item.categoria}</span>
                           <span className="px-2 py-0.5 bg-blue-50 text-[8px] font-black uppercase tracking-widest text-blue-500 rounded">{item.maturidade}</span>
                        </div>
                      </div>
                    </div>

                    <div className="flex items-center gap-8">
                      <div className="hidden md:block text-right">
                         <p className="text-[10px] font-black text-gray-300 uppercase tracking-widest">Fee Base</p>
                         <p className="text-sm font-bold text-gray-900">{formatCurrency(item.valor_base_num)}</p>
                      </div>
                      <div className="w-10 h-10 flex items-center justify-center rounded-full bg-gray-100 text-gray-400 group-hover:bg-black group-hover:text-white transition-all">
                        <svg className={`w-4 h-4 transition-transform ${expandedId === item.id ? 'rotate-180' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M19 9l-7 7-7-7"/></svg>
                      </div>
                    </div>
                  </div>

                  {expandedId === item.id && (
                    <div className="p-10 bg-white border-t border-gray-100 animate-in slide-in-from-top-4 duration-300 space-y-10">
                      <div className="grid grid-cols-1 md:grid-cols-4 gap-8">
                        {/* COLUNA 1 & 2: INFORMAÇÕES PRINCIPAIS E TAREFAS */}
                        <div className="md:col-span-2 space-y-8">
                           <div className="space-y-4">
                              <div className="space-y-2">
                                <label className="text-[9px] font-black text-gray-300 uppercase tracking-widest ml-2">Nome da Solução</label>
                                <input 
                                  value={item.solucao} 
                                  onChange={(e) => updateSolution(item.id, 'solucao', e.target.value)}
                                  className="w-full bg-gray-50 p-4 rounded-xl font-bold text-lg focus:bg-white outline-none border border-transparent focus:border-brand"
                                />
                              </div>
                              <div className="space-y-2">
                                <label className="text-[9px] font-black text-gray-300 uppercase tracking-widest ml-2">Promessa Principal</label>
                                <textarea value={item.promessa} onChange={(e) => updateSolution(item.id, 'promessa', e.target.value)} className="w-full bg-gray-50 p-4 rounded-xl font-medium text-sm focus:bg-white outline-none min-h-[80px]" />
                              </div>
                              <div className="space-y-2">
                                <label className="text-[9px] font-black text-gray-300 uppercase tracking-widest ml-2">Descrição Técnica</label>
                                <textarea value={item.descricao} onChange={(e) => updateSolution(item.id, 'descricao', e.target.value)} className="w-full bg-gray-50 p-4 rounded-xl font-medium text-sm focus:bg-white outline-none min-h-[120px]" />
                              </div>
                           </div>

                           {/* ÁREA EM BRANCO -> FASES DE ENTREGA (TAREFAS) */}
                           <div className="space-y-6 pt-6 border-t border-gray-100">
                              <div className="flex justify-between items-center">
                                 <div className="flex items-center gap-3">
                                    <div className="w-8 h-8 bg-blue-50 text-blue-600 rounded-lg flex items-center justify-center">
                                       <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2"/></svg>
                                    </div>
                                    <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Cronograma de Tarefas e Entregáveis</h4>
                                 </div>
                                 <button 
                                   onClick={() => handleGenerateDeliverables(item.id)}
                                   disabled={isGeneratingDeliverables === item.id}
                                   className="text-[8px] font-black text-blue-600 uppercase tracking-widest bg-blue-50 px-3 py-1.5 rounded-lg hover:bg-blue-100 transition-all disabled:opacity-50"
                                 >
                                   {isGeneratingDeliverables === item.id ? 'Gerando...' : '✨ Gerar via IA'}
                                 </button>
                              </div>

                              <div className="bg-gray-50 p-6 rounded-[32px] border border-gray-100 space-y-4">
                                 {item.entregaveis && item.entregaveis.length > 0 ? (
                                   <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                                      {item.entregaveis.map((task, idx) => (
                                         <div key={idx} className="flex justify-between items-center bg-white p-3.5 rounded-2xl border border-gray-100 group/task shadow-sm hover:border-blue-200 transition-all">
                                            <p className="text-[11px] font-bold text-gray-700 leading-tight flex items-center gap-3">
                                               <span className="w-5 h-5 rounded-full bg-blue-600 text-white text-[8px] flex items-center justify-center font-black shrink-0">{idx + 1}</span>
                                               <span className="truncate max-w-[180px]">{task}</span>
                                            </p>
                                            <button onClick={() => handleRemoveDeliverable(item.id, idx)} className="text-gray-300 hover:text-red-500 opacity-0 group-hover/task:opacity-100 transition-opacity">
                                               <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M6 18L18 6M6 6l12 12"/></svg>
                                            </button>
                                         </div>
                                      ))}
                                   </div>
                                 ) : (
                                   <p className="text-[10px] italic text-gray-400 text-center py-10">Nenhuma fase ou tarefa definida para esta solução.</p>
                                 )}

                                 <div className="relative pt-2">
                                    <input 
                                      placeholder="Adicionar nova fase manualmente..." 
                                      value={deliverableInputs[String(item.id)] || ''}
                                      onChange={(e) => setDeliverableInputs({...deliverableInputs, [String(item.id)]: e.target.value})}
                                      onKeyDown={(e) => e.key === 'Enter' && handleAddDeliverable(item.id)}
                                      className="w-full bg-white border border-gray-200 p-4 rounded-2xl text-[11px] font-medium outline-none pr-12 focus:border-blue-500 transition-all"
                                    />
                                    <button onClick={() => handleAddDeliverable(item.id)} className="absolute right-4 top-1/2 -translate-y-1/2 text-gray-400 hover:text-blue-600 transition-colors">
                                       <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M12 6v6m0 0v6m0-6h6m-6 0H6"/></svg>
                                    </button>
                                 </div>
                              </div>
                           </div>
                        </div>

                        {/* COLUNA 3: TAXONOMIA E PREÇO */}
                        <div className="space-y-6">
                           <div className="space-y-2">
                             <label className="text-[9px] font-black text-gray-300 uppercase tracking-widest ml-2">Metadados Técnicos</label>
                             <div className="grid grid-cols-1 gap-2">
                                <select value={item.categoria} onChange={(e) => updateSolution(item.id, 'categoria', e.target.value)} className="bg-gray-50 p-4 rounded-xl font-bold text-xs outline-none">
                                  {appConfig.config?.categories.map(c => <option key={c} value={c}>{c}</option>)}
                                </select>
                                <select value={item.maturidade} onChange={(e) => updateSolution(item.id, 'maturidade', e.target.value)} className="bg-gray-50 p-4 rounded-xl font-bold text-xs outline-none">
                                  {appConfig.config?.maturities.map(m => <option key={m} value={m}>{m}</option>)}
                                </select>
                             </div>
                           </div>
                           <div className="grid grid-cols-1 gap-4">
                              <div className="space-y-2">
                                <label className="text-[9px] font-black text-gray-300 uppercase tracking-widest ml-2">Preço Base (R$)</label>
                                <input type="number" value={item.valor_base_num} onChange={(e) => updateSolution(item.id, 'valor_base_num', parseFloat(e.target.value))} className="w-full bg-gray-50 p-4 rounded-xl font-bold text-sm" />
                              </div>
                              <div className="space-y-2">
                                <label className="text-[9px] font-black text-gray-300 uppercase tracking-widest ml-2">Duração Estimada</label>
                                <select value={item.duracao} onChange={(e) => updateSolution(item.id, 'duracao', e.target.value)} className="w-full bg-gray-50 p-4 rounded-xl font-bold text-sm">
                                  {appConfig.config?.durations.map(d => <option key={d} value={d}>{d}</option>)}
                                </select>
                              </div>
                           </div>

                           {/* TAGS DA SOLUÇÃO */}
                           <div className="space-y-2">
                             <label className="text-[9px] font-black text-gray-300 uppercase tracking-widest ml-2">Tags do Produto</label>
                             <div className="flex flex-wrap gap-1.5 p-3 bg-gray-50 rounded-xl border border-gray-100 min-h-[60px]">
                                {appConfig.config?.tags.map((tag) => {
                                  const isActive = (item.tags || []).includes(tag);
                                  return (
                                    <button 
                                      key={tag}
                                      onClick={() => toggleSolutionTag(item.id, tag)}
                                      className={`px-2 py-1 rounded-lg text-[9px] font-black uppercase transition-all ${isActive ? 'bg-blue-600 text-white shadow-lg' : 'bg-white text-gray-400 border border-gray-100 hover:bg-gray-100'}`}
                                    >
                                      #{tag}
                                    </button>
                                  );
                                })}
                             </div>
                           </div>

                           <div className="space-y-2 bg-gray-50 p-4 rounded-2xl border border-dashed border-gray-200">
                             <label className="text-[9px] font-black text-gray-400 uppercase tracking-widest block mb-2">Upsell (Opcionais)</label>
                             {item.variaveis_opcionais && item.variaveis_opcionais.length > 0 && (
                                <div className="space-y-1 mb-3">
                                   {item.variaveis_opcionais.map((v, idx) => (
                                      <div key={idx} className="flex justify-between items-center bg-white p-2 rounded-lg border border-gray-100 text-[11px]">
                                         <span className="font-bold text-gray-600 truncate mr-2">{v.label}</span>
                                         <div className="flex items-center gap-2 shrink-0">
                                            <span className="font-mono text-gray-400">{formatCurrency(v.valor)}</span>
                                            <button onClick={() => handleRemoveVariable(item.id, idx)} className="text-red-400 hover:text-red-600 font-bold px-1">×</button>
                                         </div>
                                      </div>
                                   ))}
                                </div>
                             )}
                             <div className="flex gap-2">
                                <input placeholder="Item" value={variableInputs[String(item.id)]?.label || ''} onChange={(e) => setVariableInputs({...variableInputs, [String(item.id)]: {...(variableInputs[String(item.id)]||{label:'',valor:''}), label: e.target.value}})} className="flex-[2] bg-white border border-gray-200 p-2 rounded-lg text-[10px] font-bold outline-none" />
                                <input type="number" placeholder="R$" value={variableInputs[String(item.id)]?.valor || ''} onChange={(e) => setVariableInputs({...variableInputs, [String(item.id)]: {...(variableInputs[String(item.id)]||{label:'',valor:''}), valor: e.target.value}})} className="flex-1 bg-white border border-gray-200 p-2 rounded-lg text-[10px] font-bold outline-none" />
                                <button onClick={() => handleAddVariable(item.id)} className="bg-black text-white px-3 rounded-lg font-black text-xs">+</button>
                             </div>
                           </div>
                        </div>

                        {/* COLUNA 4: FUNDAMENTOS E AÇÕES */}
                        <div className="space-y-6">
                           <div className="space-y-4">
                              <div className="space-y-2">
                                 <label className="text-[9px] font-black text-gray-300 uppercase tracking-widest ml-2">Público-Alvo Ideal</label>
                                 <textarea 
                                    value={item.publico_alvo} 
                                    onChange={(e) => updateSolution(item.id, 'publico_alvo', e.target.value)} 
                                    className="w-full bg-gray-50 p-4 rounded-xl font-medium text-xs focus:bg-white outline-none min-h-[80px]" 
                                    placeholder="Ex: Empresas de serviços com time comercial..."
                                 />
                              </div>
                              <div className="space-y-2">
                                 <label className="text-[9px] font-black text-gray-300 uppercase tracking-widest ml-2">Resultado Esperado</label>
                                 <textarea 
                                    value={item.resultado_esperado} 
                                    onChange={(e) => updateSolution(item.id, 'resultado_esperado', e.target.value)} 
                                    className="w-full bg-gray-50 p-4 rounded-xl font-medium text-xs focus:bg-white outline-none min-h-[80px]" 
                                    placeholder="Ex: Aumento de 30% na conversão..."
                                 />
                              </div>
                           </div>

                           <div className="pt-4 space-y-4">
                              <button 
                                onClick={() => handleMagicFill(item.id)}
                                disabled={isMagicFilling === item.id}
                                className="w-full bg-amber-50 text-amber-600 border border-amber-100 p-5 rounded-2xl text-[9px] font-black uppercase tracking-widest hover:bg-amber-100 transition-all flex items-center justify-center gap-2 shadow-sm"
                              >
                                {isMagicFilling === item.id ? 'Refinando Estratégia...' : '✨ Magic Fill (Inteligência Total)'}
                              </button>
                              <div className="h-px bg-gray-100 w-full"></div>
                              <button onClick={() => removeSolution(item.id)} className="w-full p-4 bg-red-50 text-red-600 rounded-xl font-black text-[9px] uppercase tracking-widest hover:bg-red-500 hover:text-white transition-all">
                                Remover Solução
                              </button>
                           </div>
                        </div>
                      </div>
                    </div>
                  )}
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      {/* METAS TAB */}
      {activeTab === 'metas' && (
        <div className="max-w-4xl mx-auto space-y-12">
           <div className="app-card p-12 bg-white space-y-10">
              <div className="flex justify-between items-end mb-10">
                 <h2 className="text-3xl font-black text-gray-900 tracking-tighter">Metas de Faturamento</h2>
                 <button onClick={saveGoals} className="px-8 py-3 bg-black text-white rounded-2xl font-black text-[10px] uppercase tracking-widest">Salvar Metas</button>
              </div>
              <div className="divide-y divide-gray-50 border border-gray-50 rounded-3xl overflow-hidden">
                {goals.map(g => (
                  <div key={g.month} className="flex items-center justify-between p-6 hover:bg-gray-50">
                    <span className="font-bold text-gray-600">{formatMonth(g.month)}</span>
                    <input type="number" value={g.target} onChange={e => updateGoal(g.month, parseFloat(e.target.value))} className="bg-white border border-gray-200 p-2 rounded-xl font-bold text-right w-40" />
                  </div>
                ))}
              </div>
           </div>
        </div>
      )}

      {/* SYSTEM TAB */}
      {activeTab === 'system' && (
        <div className="max-w-5xl mx-auto space-y-12 animate-in fade-in slide-in-from-bottom-4 duration-500">
           <div className="app-card p-12 bg-white space-y-16 shadow-2xl rounded-[40px] border border-gray-100">
              <div className="flex justify-between items-start border-b border-gray-50 pb-10">
                 <div>
                    <h2 className="text-3xl font-black text-gray-900 tracking-tighter uppercase italic">Configurações Base</h2>
                    <p className="text-gray-400 font-bold uppercase text-[10px] tracking-widest mt-2">Personalize a taxonomia e o motor técnico do sistema</p>
                 </div>
                 <button onClick={saveCustomization} disabled={isSyncing} className="px-12 py-5 bg-blue-600 text-white rounded-[30px] font-black text-xs uppercase tracking-widest hover:scale-105 transition-all shadow-xl shadow-blue-500/20">
                   {isSyncing ? 'Sincronizando...' : 'Aplicar Alterações'}
                 </button>
              </div>

              {/* 1. Módulos Ativos */}
              <section className="space-y-8">
                 <div className="flex items-center gap-4">
                    <div className="w-10 h-10 bg-black rounded-xl flex items-center justify-center text-lg">🧩</div>
                    <h3 className="text-xl font-black text-gray-900 uppercase tracking-tighter">1. Gestão de Módulos (Visibilidade)</h3>
                 </div>
                 <div className="grid grid-cols-2 md:grid-cols-5 gap-4">
                    {['dashboard', 'copilot', 'fichario', 'catalogo', 'pdf_builder'].map(m => {
                       const isActive = appConfig.config?.enabledModules.includes(m);
                       return (
                          <button key={m} onClick={() => toggleModule(m)} className={`p-6 rounded-[24px] border flex flex-col items-center gap-3 transition-all ${isActive ? 'bg-black text-white border-black' : 'bg-gray-50 text-gray-400 border-transparent'}`}>
                             <div className={`w-2 h-2 rounded-full ${isActive ? 'bg-blue-500' : 'bg-gray-300'}`}></div>
                             <span className="text-[10px] font-black uppercase tracking-widest text-center">{m.replace('_', ' ')}</span>
                          </button>
                       );
                    })}
                 </div>
              </section>

              {/* 2. Taxonomia de Catálogo */}
              <section className="space-y-10">
                 <div className="flex items-center gap-4">
                    <div className="w-10 h-10 bg-gray-100 rounded-xl flex items-center justify-center text-lg">📁</div>
                    <h3 className="text-xl font-black text-gray-900 uppercase tracking-tighter">2. Taxonomia Dinâmica</h3>
                 </div>
                 <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                    {/* Tags */}
                    <div className="space-y-4">
                       <label className="text-[10px] font-black text-blue-500 uppercase tracking-widest">Tags Globais (Filtragem)</label>
                       <div className="flex flex-wrap gap-2 p-5 bg-blue-50/50 rounded-3xl border border-blue-100 min-h-[100px]">
                          {appConfig.config?.tags.map((tag, i) => (
                             <span key={i} className="px-3 py-1.5 bg-white border border-blue-200 rounded-xl text-[10px] font-bold text-blue-600 flex items-center gap-2">
                                #{tag}
                                <button onClick={() => handleRemoveTaxonomy('tags', i)} className="text-blue-300 hover:text-blue-600">×</button>
                             </span>
                          ))}
                          <input placeholder="Nova tag..." className="bg-transparent text-[10px] font-bold outline-none w-24 p-1" onKeyDown={e => { if(e.key === 'Enter') { handleAddTaxonomy('tags', e.currentTarget.value); e.currentTarget.value = ''; } }} />
                       </div>
                    </div>
                    {/* Maturidades */}
                    <div className="space-y-4">
                       <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Níveis de Maturidade</label>
                       <div className="flex flex-wrap gap-2 p-5 bg-gray-50 rounded-3xl border border-gray-100 min-h-[100px]">
                          {appConfig.config?.maturities.map((m, i) => (
                             <span key={i} className="px-3 py-1.5 bg-white border border-gray-200 rounded-xl text-[10px] font-bold flex items-center gap-2">
                                {m}
                                <button onClick={() => handleRemoveTaxonomy('maturities', i)} className="text-red-400 hover:text-red-600">×</button>
                             </span>
                          ))}
                          <input placeholder="Adicionar..." className="bg-transparent text-[10px] font-bold outline-none w-24 p-1" onKeyDown={e => { if(e.key === 'Enter') { handleAddTaxonomy('maturities', e.currentTarget.value); e.currentTarget.value = ''; } }} />
                       </div>
                    </div>
                    {/* Durações */}
                    <div className="space-y-4">
                       <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Padrões de Duração</label>
                       <div className="flex flex-wrap gap-2 p-5 bg-gray-50 rounded-3xl border border-gray-100 min-h-[100px]">
                          {appConfig.config?.durations.map((d, i) => (
                             <span key={i} className="px-3 py-1.5 bg-white border border-gray-200 rounded-xl text-[10px] font-bold flex items-center gap-2">
                                {d}
                                <button onClick={() => handleRemoveTaxonomy('durations', i)} className="text-red-400 hover:text-red-600">×</button>
                             </span>
                          ))}
                          <input placeholder="Ex: 24 meses" className="bg-transparent text-[10px] font-bold outline-none w-24 p-1" onKeyDown={e => { if(e.key === 'Enter') { handleAddTaxonomy('durations', e.currentTarget.value); e.currentTarget.value = ''; } }} />
                       </div>
                    </div>
                    {/* Categorias */}
                    <div className="space-y-4">
                       <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Categorias de Solução</label>
                       <div className="flex flex-wrap gap-2 p-5 bg-gray-50 rounded-3xl border border-gray-100 min-h-[100px]">
                          {appConfig.config?.categories.map((c, i) => (
                             <span key={i} className="px-3 py-1.5 bg-white border border-gray-200 rounded-xl text-[10px] font-bold flex items-center gap-2">
                                {c}
                                <button onClick={() => handleRemoveTaxonomy('categories', i)} className="text-red-400 hover:text-red-600">×</button>
                             </span>
                          ))}
                          <input placeholder="Add..." className="bg-transparent text-[10px] font-bold outline-none w-24 p-1" onKeyDown={e => { if(e.key === 'Enter') { handleAddTaxonomy('categories', e.currentTarget.value); e.currentTarget.value = ''; } }} />
                       </div>
                    </div>
                 </div>
              </section>

              {/* 3. Motor de Inteligência */}
              <section className="space-y-10 pt-10 border-t border-gray-50">
                 <div className="flex items-center gap-4">
                    <div className="w-10 h-10 bg-amber-50 rounded-xl flex items-center justify-center text-lg">🧠</div>
                    <h3 className="text-xl font-black text-gray-900 uppercase tracking-tighter">3. Motor de IA (Técnico)</h3>
                 </div>
                 <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                    <div className="space-y-4">
                       <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Modelo de Texto</label>
                       <select value={appConfig.config?.aiModelText} onChange={e => setAppConfig({...appConfig, config: { ...appConfig.config!, aiModelText: e.target.value as any }})} className="w-full bg-gray-50 p-5 rounded-2xl font-bold text-xs">
                          <option value="gemini-3-pro-preview">Gemini 3 Pro (Recomendado)</option>
                          <option value="gemini-3-flash-preview">Gemini 3 Flash (Veloz)</option>
                       </select>
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                        <div className="space-y-4">
                           <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Max Tokens</label>
                           <input type="number" value={appConfig.config?.aiMaxTokens} onChange={e => setAppConfig({...appConfig, config: { ...appConfig.config!, aiMaxTokens: parseInt(e.target.value) }})} className="w-full bg-gray-50 p-5 rounded-2xl font-bold text-xs" />
                        </div>
                        <div className="space-y-4">
                           <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Thinking Budget</label>
                           <input type="number" value={appConfig.config?.aiThinkingBudget} onChange={e => setAppConfig({...appConfig, config: { ...appConfig.config!, aiThinkingBudget: parseInt(e.target.value) }})} className="w-full bg-gray-50 p-5 rounded-2xl font-bold text-xs" />
                        </div>
                    </div>
                 </div>
              </section>

              {/* 4. Auditoria de Status */}
              <section className="space-y-8 pt-10 border-t border-gray-50">
                 <div className="flex items-center gap-4">
                    <div className="w-10 h-10 bg-emerald-50 rounded-xl flex items-center justify-center text-lg">📡</div>
                    <h3 className="text-xl font-black text-gray-900 uppercase tracking-tighter">4. Status da Infraestrutura</h3>
                 </div>
                 <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                    <div className="p-6 bg-gray-50 rounded-3xl flex justify-between items-center">
                       <span className="text-[10px] font-black text-gray-400 uppercase">API Key IA</span>
                       <span className="px-3 py-1 bg-green-100 text-green-700 rounded-full text-[9px] font-black uppercase tracking-widest">Configurada</span>
                    </div>
                    <div className="p-6 bg-gray-50 rounded-3xl flex justify-between items-center">
                       <span className="text-[10px] font-black text-gray-400 uppercase">Supabase DB</span>
                       <span className="px-3 py-1 bg-green-100 text-green-700 rounded-full text-[9px] font-black uppercase tracking-widest">Conectado</span>
                    </div>
                    <div className="p-6 bg-gray-50 rounded-3xl flex justify-between items-center">
                       <span className="text-[10px] font-black text-gray-400 uppercase">Google Workspace</span>
                       <span className="px-3 py-1 bg-blue-100 text-blue-700 rounded-full text-[9px] font-black uppercase tracking-widest">Ativo</span>
                    </div>
                 </div>
              </section>
           </div>
        </div>
      )}
    </div>
  );
};

export default AdminSettings;

export type ModuleStatus = 'ATIVA' | 'EM CONSTRUÇÃO' | 'DRAFT' | 'REVIEW' | 'PUBLISHED' | 'ARCHIVED';
export type SourceType = 'Drive' | 'Manual' | 'IA';
export type UserRole = 'MASTER' | 'USER';

export type SolutionCategory = string; // Mudado de Union para string para permitir dinamismo
export type SolutionSubCategory = string;
export type SolutionDuration = string;
export type SolutionMaturity = string;

export interface PriceOption {
  label: string;
  valor: number;
}

export interface SolutionItem {
  id: string | number;
  solucao: string;
  descricao?: string;
  promessa: string;
  categoria: SolutionCategory;
  subcategoria: SolutionSubCategory;
  duracao: SolutionDuration;
  maturidade: SolutionMaturity;
  is_favorite?: boolean; 

  // Precificação
  fee_mensal: string; 
  valor_base_num: number;
  variaveis_opcionais: PriceOption[]; 

  publico_alvo?: string;
  resultado_esperado?: string;
  diferenciais?: string[]; 
  dica_venda: string;
  link?: string;
  entregaveis?: string[];
  // Fix: Added missing tags property for SolutionItem
  tags?: string[];
}

export interface ProposalItem {
  instanceId: string; 
  solutionId: string | number;
  name: string;
  basePrice: number;
  selectedOptions: PriceOption[];
  totalPrice: number;
  duration: string;
  description?: string;
  deliverables?: string[];
  promessa?: string;
  category?: string;
  subCategory?: string; 
  maturity?: string; 
  targetAudience?: string; 
  expectedResult?: string; 
}

export interface StrategicMapItem {
  current: string;
  desired: string;
}

export interface ProposalMetadata {
  clientName: string;
  industry: string;
  website?: string;
  instagram?: string;
  meetingNotesPains?: string;
  meetingNotesDesires?: string;
  observations?: string;
  date: string;
  consultant: string;
  headline?: string;
  discountType?: 'fixed' | 'percentage';
  discountValue?: number;
}

export interface ProposalRecord {
  id: string;
  client_name: string;
  industry: string;
  total_value: number;
  consultant: string;
  items: ProposalItem[];
  metadata: ProposalMetadata;
  created_at: string;
  status?: 'PENDING' | 'APPROVED' | 'REJECTED';
}

export interface ProposalSections {
  cover: boolean;
  strategicMap: boolean;
  tacticalScope: boolean;
  finalInvestment: boolean;
  backCover: boolean;
}

export interface MonthlyGoal {
  month: string; 
  target: number;
}

export interface SystemConfig {
  categories: string[];
  subCategories: string[];
  durations: string[];
  maturities: string[];
  // Fix: Added missing tags property for SystemConfig
  tags: string[];
  defaultProposalSections: ProposalSections;
  slaThreshold: number; // Valor de faturamento para lead qualificado
  aiModelText: 'gemini-3-flash-preview' | 'gemini-3-pro-preview';
  aiModelImage: 'gemini-2.5-flash-image' | 'gemini-3-pro-image-preview';
  // Fix: Added missing technical and integration configuration properties used in AdminSettings
  aiMaxTokens: number;
  aiThinkingBudget: number;
  driveFolderId?: string;
  syncJobId?: string;
  enabledModules: string[];
}

export interface AppCustomization {
  companyName: string;
  systemLogoUrl: string;
  proposalLogoUrl: string;
  primaryColor: string;
  config?: SystemConfig; // Configurações técnicas integradas
}

export interface PlaybookModule {
  id: string;
  category: 'BASE' | 'PRODUTIZACAO' | 'EXECUCAO' | 'SISTEMA' | 'FERRAMENTAS';
  title: string;
  description: string;
  status: ModuleStatus;
  version: string;
  source: SourceType;
  type: ContentType;
  icon: string;
  permissions: UserRole[];
  content?: string;
  schema?: string[];
  data?: any[];
}

export type ContentType = 'page' | 'database' | 'template' | 'asset' | 'calculator' | 'script' | 'sla_rule' | 'learning_path' | 'admin' | 'dashboard' | 'fichario' | 'pdf_builder' | 'presentation' | 'copilot';

export interface ChatMessage {
  role: 'user' | 'assistant';
  content: string;
}

export interface AIConfig {
  systemInstruction: string;
  architectInstruction?: string;
  temperature: number;
  maxOutputTokens: number;
  thinkingBudget: number;
}

export interface FicharioFolder {
  id: string;
  name: string;
  icon: string;
  file_types: string[];
  is_system?: boolean;
}

export interface FicharioFile {
  id: string; 
  name: string;
  type: string;
  url: string;
  thumbnail: string;
  size: string;
  updatedAt: string;
  virtual_folder_id?: string;
  previewUrl: string;
  downloadUrl: string;
}

export interface ScriptPhase {
  id: string;
  name: string;
  description: string;
  objectives: string[];
  required_keywords: string[];
  checklist: string[];
  duration_sec: number;
  suggestion_templates: string[];
}

export interface ScriptDefinition {
  id: string;
  name: string;
  version: string;
  description: string;
  phases: ScriptPhase[];
}

export interface AssistSession {
  id: string;
  client_name: string;
  script_id: string;
  status: 'active' | 'completed' | 'aborted';
  started_at: string;
}

export interface TranscriptSegment {
  id: string;
  speaker: 'seller' | 'client' | 'unknown';
  text: string;
  timestamp: number;
  isFinal: boolean;
}

export interface CopilotState {
  currentPhaseIndex: number;
  checklist: Record<string, boolean>; 
  transcript: TranscriptSegment[];
  suggestions: string[];
  isRecording: boolean;
}
